INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('7baab2ba-1773-41d3-8cc6-4a9f700acd59', 'Hidup Kedua, Cinta Sejati Menanti', 'Di kehidupan sebelumnya, Nadya Lestari menikah dengan Raka Wirawan, pria yang paling ia cintai. Tapi demi wanita pujaan hatinya, Raka justru menguras habis harta keluarga Nadya dan membiarkan keluarganya hancur. Takdir memberinya kesempatan kedua. Kali ini, Nadya kembali ke titik hidupnya saat harus memilih pasangan hidup. Tanpa ragu, ia memilih Dimas Pranata, pria yang tulus dan bermoral. Saat Raka sadar Nadya tak lagi memilihnya, penyesalan pun datang... tapi semuanya sudah terlambat.

[BookID: 31001070612]', 'https://stream.shortlovers.id/Hidup_Kedua,_Cinta_Sejati_Menanti/cover.jpg', 'https://stream.shortlovers.id/Hidup_Kedua,_Cinta_Sejati_Menanti/cover.jpg', '["Romance","Drama"]', '["GoodShort","Indonesian"]', 70, 0, 2, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'Indonesia', 'Indonesian', 1770104924, 1771183676);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexl990000hx5e4pycn1o5', '800 Ribu Beli Dunia Kultivasi', 'Rizky yang sakit parah menggunakan sisa uangnya membeli sebuah aquarium misterius, yang ternyata terhubung dengan dunia kultivasi. Dengan menggunakan benda biasa seperti tusuk gigi dan baterai, dia menjadi "Kaisar Langit" yang menyelamatkan Indah, murid Sekte Petir. Ikatan menakjubkan ini menciptakan kisah cinta antar dimensi.', 'https://stream.shortlovers.id/melolo/800-ribu-beli-dunia-kultivasi/cover.jpg', NULL, '["Serangan balik","Pemeran Utama Pria","Fantasi perkotaan","Time Travel"]', '[]', 80, 4.1, 4913, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570447, 1770834191);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexll8004hhx5e4qx99qtv', 'Ahli Pengobatan Sakti', 'Dr. Surya, seorang tabib agung yang menyembunyikan identitasnya sebagai menantu titipan, diam-diam membantu istrinya mengelola perusahaan. Saat ia hendak mengungkap jati dirinya, sang istri justru meragukannya dan meminta cerai, memicu konflik emosional yang mendalam.', 'https://stream.shortlovers.id/melolo/ahli-pengobatan-sakti/cover.jpg', NULL, '["Fantasi"]', '[]', 123, 4.7, 1608, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570447, 1770931754);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexmag00bchx5e1yt6lnfd', 'Aku Kaya dari Giok', 'Sejak kena pukul di tambang, Rizky Santoso tiba-tiba dapat kemampuan tembus pandang. Dunia giok pun langsung berubah total. Orang lain tebak giok pakai ilmu mistis, sementara dia bisa lihat isi batu kayak X-Ray dan nemu Giok Raja dari limbah. Waktu Rizky ambil alih wilayah itu, bos besar tambang langsung berubah sikap.', 'https://stream.shortlovers.id/melolo/aku-kaya-dari-giok/cover.jpg', NULL, '["Bisnis"]', '[]', 112, 4.9, 3461, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570448, 1770931755);
