INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexn9m00q7hx5ea171efcy', 'Anak Ajaib Ahli Barang Antik', 'Yansen yang berusia delapan tahun adalah penerus ke-13 Toko Gadai Benda Ajaib. Dia ditinggal kakeknya sendirian untuk menjaga toko. Dengan mata ajaibnya, dia dapat menilai barang berharga. Yansen membeli barang-barang berenergi jahat dengan harga murah, lalu memurnikannya, dan menjualnya lagi dengan harga tinggi.', 'https://stream.shortlovers.id/melolo/anak-ajaib-ahli-barang-antik/cover.jpg', NULL, '["Drama Keluarga","Fantasi"]', '[]', 117, 4.5, 1193, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570450, 1770931756);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexnjr00wqhx5eqj0ah1jj', 'Antara Ambisi dan Cinta', 'Husain, tiba-tiba kembali ke 2002—tepat di hari pertamanya mendaftar kuliah. Dengan pengetahuan masa depan sebagai “senjata rahasia”, ia mulai memperluas jaringan, menaklukkan dunia e-commerce, dan mendirikan perusahaan ekspedisi “Rocket 101” untuk menangkap gelombang bisnis yang sedang naik daun.', 'https://stream.shortlovers.id/melolo/antara-ambisi-dan-cinta/cover.jpg', NULL, '["Kelahiran kembali","Pemeran Utama Pria","Pertanian Perkotaan","Serangan balik"]', '[]', 147, 4.4, 1700, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570450, 1770639272);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexnvg014xhx5ewz56qlqm', 'Ayah Berandalan jadi CEO', 'Lisa masuk ke tubuh gadis kecil di hari dia genap dewasa. Tubuh ini milik anak yang selalu disiksa orang tuanya sampai mati kelaparan! Dia tiba-tiba minta tukar ayahnya jadi berandalan. Sebagai putri mahkota, melatih berandalan itu hal sepele.', 'https://stream.shortlovers.id/melolo/ayah-berandalan-jadi-ceo/cover.webp', NULL, '["Drama Keluarga","Bisnis"]', '[]', 66, 4.3, 2004, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570450, 1771067576);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexo2c018mhx5e664g1qvy', 'Ayah Tiri Baru, Lindungi 6 Anak', 'Pak Surya masuk ke dunia novel dan menjadi ayah tiri enam anak yang kelak jadi penjahat. Dengan Sistem Ayah Super, ia melindungi mereka dari bahaya, mencegah penjualan anak, mengusir penculik dan memastikan sekolah. Perlahan ia meraih kepercayaan mereka, menghadapi tantangan hidup, mengubah nasib dan menemukan arti keluarga.', 'https://stream.shortlovers.id/melolo/ayah-tiri-baru-lindungi-6-anak/cover.jpg', NULL, '["Serangan balik","Pemeran Utama Pria","Imajinasi Perkotaan","Sistem","Time Travel"]', '[]', 80, 4.3, 4196, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570451, 1771023867);
