INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexp8h01iihx5evkyyi3c0', 'Balas Dendam Sang Putri Genius', 'Indira, gadis genius yang difitnah dan dikirim ke rumah sakit jiwa oleh keluarga dan Laras, bangkit menjadi sosok kuat. Setelah keluar, ia lawan perlakuan buruk keluarga, bongkar kebusukan Laras di Pesta Juara Nasional dan ungkap identitas geniusnya. Keluarganya menyesal, tapi Indira meninggalkan mereka dan hidup mandiri.', 'https://stream.shortlovers.id/melolo/balas-dendam-sang-putri-genius/cover.jpg', NULL, '["Pemeran Utama Wanita Kuat","Serangan balik","Romansa","Pertumbuhan Wanita","Swap Identitas"]', '[]', 52, 4.6, 2663, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570452, 1770710011);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexpqs01lfhx5ean0pmmx4', 'Bangkit Setelah Ditinggalkan', 'Selama lima tahun, Rizky Prasetyo rela menjadi ayah rumah tangga demi keluarga dan putrinya, Nadia, serta mendukung Yani Pratama membangun karier. Saat Yani sukses, keluarga Pratama malah menghina dan memaksanya bercerai. Dipermalukan dan disakiti di depan anaknya, Rizky akhirnya memutuskan untuk bangkit dan mengubah nasibnya.', 'https://stream.shortlovers.id/melolo/bangkit-setelah-ditinggalkan/cover.jpg', NULL, '["Serangan balik","Pemeran Utama Pria","Imajinasi Perkotaan","Lainnya","Sistem"]', '[]', 80, 4.7, 4425, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570453, 1770621810);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexq9601pwhx5ede2mnbau', 'Barang Supermarket di Dunia Kuno', 'Arif secara tak sengaja terperangkap ke zaman kuno, memasuki tubuh seorang pemuda boros. Hidupnya hancur akibat kebiasaan judi dan utang, bahkan istrinya akan dijual untuk melunasi utang. Namun, dia menemukan ruang modern berisi supermarket besar yang bisa diakses dengan pikirannya, memberi kesempatan untuk membalikkan nasib.', 'https://stream.shortlovers.id/melolo/barang-supermarket-di-dunia-kuno/cover.webp', NULL, '["Drama","Romantis","Aksi"]', '[]', 72, 4.6, 3958, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570453, 1771180926);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexqlg01txhx5e8q18u8tj', 'Bersinar Setelah Cerai', 'Setelah bercerai karena tuntutan materi, Rizky Pratama tiba-tiba mendapatkan Sistem Sultan yang mengubah hidupnya. Ia membeli rumah mewah, membantu Indah Pratiwi yang sedang terluka, dan menghadapi keluarga Sinta yang berusaha merebut hartanya. Dengan bukti legal, Rizky membuat mereka menerima akibatnya.', 'https://stream.shortlovers.id/melolo/bersinar-setelah-cerai/cover.jpg', NULL, '["Kembali","Pemeran Utama Pria","Fantasi perkotaan","Serangan balik","Identitas Tersembunyi"]', '[]', 80, 4.2, 3189, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570454, 1770670616);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexr3a01yehx5erexomg2u', 'Bos Datang Malah diajak Nguli', 'Rizky mendapat sistem role play. Tiap memerankan profesi, ia dapat hadiah. Saat jadi pekerja bangunan, ia mengira Lani Cahaya yang datang inspeksi adalah pekerja baru dan mengajaknya angkat bata. Lani kagum, ingin merekrutnya, tapi Rizky sering ganti profesi. Lani terus mengejar hingga mereka akhirnya menikah.', 'https://stream.shortlovers.id/melolo/bos-datang-malah-diajak-nguli/cover.webp', NULL, '["Bisnis"]', '[]', 80, 4.7, 2262, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570455, 1771094544);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexrc5022vhx5emfxz1u4v', 'Bos Supermarket yang Hebat', 'Setelah gajinya dipotong, Arif Cahya memilih untuk mengundurkan diri dan secara tidak sengaja terhubung dengan Sistem Rugi yang membuatnya untung tiap kali dia merugi. Dia membeli supermarket yang hampir bangkrut dan berusaha untuk merugi. Namun, bisnisnya justru untung dan dia terjebak dalam siklus yang aneh.', 'https://stream.shortlovers.id/melolo/bos-supermarket-yang-hebat/cover.jpg', NULL, '["Kehidupan perkotaan","Pemeran Utama Pria","Sistem"]', '[]', 80, 4.1, 2665, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570455, 1770836982);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexrow027chx5ewztcofht', 'Bukan Lagi Budak Cintamu', 'Sebuah kecelakaan membuat Chiko Pratama terlahir kembali di hari ia ditolak oleh primadona kampus, Yuni Suryani. Ia meninggalkan obsesinya sebagai bucin, bertekad meraih sukses dengan ingatan masa lalunya. Namun, Yuni yang dulu menolaknya kini panik dan mulai mengejarnya. Kisah pembalikan nasib dan cinta mereka pun dimulai.', 'https://stream.shortlovers.id/melolo/bukan-lagi-budak-cintamu/cover.jpg', NULL, '["Tycoon","Kelahiran kembali","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik"]', '[]', 89, 4.2, 1042, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570455, 1770621814);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexryb02cbhx5e44yzsw3n', 'Cindy si Cerdik', 'Danny, ayah Cindy, adalah pejudi yang payah. Sementara itu, Cindy berguru di kota agar bisa menang judi. Setelah itu, Cindy pulang dengan tabungannya dan minta diajak berjudi. Kemudian, Cindy bermain dan mengalahkan Gultom dengan ilmunya. Cindy membiarkan dia lengah lalu berusaha menebus kekalahan ayahnya.', 'https://stream.shortlovers.id/melolo/cindy-si-cerdik/cover.webp', NULL, '["Drama","Keluarga"]', '[]', 60, 4.6, 3777, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570456, 1771180926);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexsiq02fohx5e25cg3g2e', 'Dari Memancing Menjadi Kaya', 'Arif dapat sistem memancing ajaib, hidupnya berubah. Dia beli vila dan mobil mewah, bikin mertua malu, selamatkan keluarga dan lawan musuh. Di kampung, ia buktikan kekayaan dan habisi penghina. Akhirnya, demi bantu negara kuasai teknologi chip, ia serahkan desain rahasia.', 'https://stream.shortlovers.id/melolo/dari-memancing-menjadi-kaya/cover.jpg', NULL, '["Tycoon","Serangan balik","Pemeran Utama Pria","Imajinasi Perkotaan","Kekuatan super"]', '[]', 79, 4.7, 1913, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570456, 1770621816);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexswp02k3hx5ecxpbmm8o', 'Dendam di Atas Luka', 'Di Kota Hurto, nggak ada yang berani mengusik Lucas karena dilindungi oleh istrinya, Yuna, teman masa kecilnya, Sinta, dan adiknya, Yanti. Tapi di ulang tahunnya yang ke-29, Yanti diseret ke gang gelap dan mati dilecehkan...', 'https://stream.shortlovers.id/melolo/dendam-di-atas-luka/cover.jpg', NULL, '["Harem","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik","Keluarga"]', '[]', 60, 4.3, 1821, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570457, 1770621817);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleext6402nghx5eh2fnx9ps', 'Dewa Balapan', 'Rizky Pratama, mantan legenda balap, kembali turun gunung setelah menolong Putri Fitria di perjalanan menuju bandara. Ia harus mengumpulkan Empat Komponen Legenda untuk menyingkirkan murid sesatnya. Mengalahkan rival dengan taksi, ia meraih Roda Macan Putih dan melangkah ke tantangan berikutnya.', 'https://stream.shortlovers.id/melolo/dewa-balapan/cover.jpg', NULL, '["Kembali","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik"]', '[]', 71, 4, 750, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570457, 1771146697);
