INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexttr02vuhx5ei2oknpov', 'Dikurung, Aku Memanggil Petir', 'Tyson, putra kandung Keluarga Sukma, hidup di luar 14 tahun. Ayahnya bawa dia pulang, tapi dia terus dianiaya keluarganya. Jiwanya pindah ke dunia lain dan berkultivasi 800 tahun. Setelah gagal lewati cobaan, dia kembali ke Planet Biru dan bersumpah untuk tidak menjadi penjilat Keluarga Sukma lagi.', 'https://stream.shortlovers.id/melolo/dikurung-aku-memanggil-petir/cover.jpg', NULL, '["Panglima Perang","Serangan balik","Pemeran Utama Pria","Fantasi perkotaan","Time Travel"]', '[]', 79, 4, 4097, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570458, 1770836984);
