INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexudo033mhx5ed3ifjk6w', 'Dokter Sakti Jadi Rebutan', 'Setelah gurunya tiada, Arif Pratama turun gunung untuk melaksanakan perjodohan. Di perjalanan, Arif tanpa sengaja menyelamatkan Stephanie Liem. Begitu menemui keluarga calonnya, Arif malah ditolak. Akhirnya, Stephanie muncul dan identitas Arif sebagai dokter sakti perlahan terungkap.', 'https://stream.shortlovers.id/melolo/dokter-sakti-jadi-rebutan/cover.jpg', NULL, '["Dokter","Serangan balik","Pemeran Utama Pria","Fantasi perkotaan"]', '[]', 80, 4.7, 689, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570459, 1771194361);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexukt0383hx5ewjk5efxh', 'Jenderal Terakhir', 'Di dunia kultivasi, Rizky menggantikan adiknya masuk militer dan naik jadi Jenderal Enam Bintang. Ayahnya memaksanya menyerahkan jasa perang, memicu putus hubungan. Saat ayahnya berkhianat dan berupaya membungkamnya, Rizky selamat, kembali sebagai pahlawan, dan membongkar semua kejahatan.', 'https://stream.shortlovers.id/melolo/jenderal-terakhir/cover.jpg', NULL, '["Kembali","Pemeran Utama Pria","Imajinasi Perkotaan","Panglima Perang","Serangan balik"]', '[]', 72, 4.6, 2779, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570459, 1770670644);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexuum03c4hx5ekn2nl7s0', 'Dunia Menyayangiku Penuh Kelembutan', 'Rossy Yantama sejak kecil merasa rendah diri karena adanya tanda lahir di wajahnya. Saat kuliah, dia dipaksa oleh keluarganya untuk bekerja dan mencari nafkah. Namun, saat bekerja, dia mengalami bahaya dan diselamatkan oleh Yanwar Sijabat, seorang pewaris tunggal keluarga kaya raya. Rossy secara tak terduga hamil, dan kemudian dijemput oleh Yanwar. Seiring berjalannya waktu, mereka saling jatuh cinta, dan secara tidak terduga, misteri asal-usul Rossy pun terungkap...', 'https://stream.shortlovers.id/melolo/dunia-menyayangiku-penuh-kelembutan/cover.jpg', NULL, '["Romansa Urban","Romansa","Ceo","Perbedaan usia","Cinta Satu Malam"]', '[]', 95, 4.2, 628, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570459, 1770621821);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexv3c03hfhx5eny2bhsma', 'Gadis Lemah itu Sudah Mati', 'Dulu, Anna tertipu Pasha sampai hancur. Hatinya, hidupnya, semuanya lenyap. Tapi setelah hidup kembali, dia tak lagi jadi boneka. Dia kembali sebagai wanita galak, pemberani, tak kenal ampun. Dendam jadi tujuannya, sampai takdir datang membawa sesuatu yang tak terduga.', 'https://stream.shortlovers.id/melolo/gadis-lemah-itu-sudah-mati/cover.jpg', NULL, '["Pemeran Utama Wanita Kuat","Kelahiran kembali","Romansa","Romansa Urban","Pewaris"]', '[]', 100, 4.4, 5043, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570460, 1770621822);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexvd903n0hx5em36d0s06', 'Gagal Ujian Jadi Playboy Istana', 'Raden Pratama gagal meraih impian karena dijebak dan dipenjara. Berkat bantuan sahabat lamanya yang kini menjadi kasim, ia mendapat kesempatan menjadi pendamping Putri Cempaka. Dengan kecerdikan dan tekad, Pratama memilih jalan baru di istana, berambisi menguasai kekuasaan dan hati para wanita.', 'https://stream.shortlovers.id/melolo/gagal-ujian-jadi-playboy-istana/cover.jpg', NULL, '["Harem","Pemeran Utama Pria","Imajinasi Pria","Serangan balik","Sistem"]', '[]', 82, 4.3, 1960, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570460, 1770672812);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexvle03rlhx5e7zyk373z', 'Guru Kecil Genius', 'Pertapa yang miskin nggak mampu biayai muridnya, Maya. Maya dibimbing berlindung pada Kepala Klub Catur Hitam Putih, Surya. Nggak terduga, Maya mengejutkan semua orang dengan pecahkan Catur Naga Sejati yang belum terpecahkan selama 20 tahun dan menerima tantangan Raja Catur dengan tenang.', 'https://stream.shortlovers.id/melolo/guru-kecil-genius/cover.webp', NULL, '["Kehidupan"]', '[]', 87, 4.8, 3686, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570460, 1771091436);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexvuu03wghx5efud1gfz2', 'Habis Wabah, Lumbungku Penuh', 'Setelah terbangun di tubuh Arga Pratama, anak ketiga keluarga Pratama di desa kuno, hidupnya berubah total. Dulunya pemuda malas dan dibenci, kini Arga mendapat sistem ajaib. Dengan kecerdikannya, ia menafkahi keluarga, menumpas orang jahat, dan perlahan membawa keluarganya menuju hidup makmur.', 'https://stream.shortlovers.id/melolo/habis-wabah-lumbungku-penuh/cover.jpg', NULL, '["Bukan siapa-siapa","Sistem","Pemeran Utama Pria","Drama Sejarah","Lainnya"]', '[]', 90, 4.5, 1584, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570461, 1770621825);
