INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexwt40493hx5eof1iepw3', 'Ibu Kembali, Anak Berebut Kasih', 'Setelah kecelakaan tragis, Dewi Lestari terbangun di masa depan dan menyaksikan anak-anaknya hidup dalam kesedihan. Kini, ia berjuang mengubah nasib keluarga, menghadapi persaingan dan konflik di antara anak-anaknya demi kebahagiaan mereka.', 'https://stream.shortlovers.id/melolo/ibu-kembali-anak-berebut-kasih/cover.jpg', NULL, '["Serangan balik","Romansa","Drama Keluarga","Keluarga","Time Travel"]', '[]', 68, 4.2, 2997, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570462, 1770621827);
