INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexy9h04sihx5eyn47m3iz', 'Kakek 10 Tahun Tak Terkalahkan', 'Pada 1976, Arya, juara dunia catur Go, pulang kampung dan bertemu dua dewa yang bermain Go. Setelah bergantian satu ronde, 49 tahun pun berlalu. Berkat persik keabadian, ia menjadi anak 10 tahun dan pulang pada 2025. Dihina keluarga, Arya memecahkan Papan Catur Agung, menyadarkan istri, dan ungkap krisis keluarga yang ternyata…', 'https://stream.shortlovers.id/melolo/kakek-10-tahun-tak-terkalahkan/cover.jpg', NULL, '["Identitas Tersembunyi","Pemeran Utama Pria","Imajinasi Perkotaan","Serangan balik","Keluarga"]', '[]', 73, 4.2, 2859, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570464, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexyhq04wlhx5esdd66m11', 'Kakek Muda Pembawa Berkah', 'Dr. Fadli, berusia 60 tahun tapi berparas 20 tahun, kembali ke Bumi setelah gagal ujian kultivasi 600 tahun. Ketika kembali ia mendapati keluarganya terpuruk. Ia pun kemudian menggunakan kekuatan kultivasi untuk menyembuhkan, melindungi, dan membangun kejayaan keluarga Fadli.', 'https://stream.shortlovers.id/melolo/kakek-muda-pembawa-berkah/cover.jpg', NULL, '["Serangan balik","Pemeran Utama Pria","Fantasi perkotaan","Lainnya","Time Travel"]', '[]', 80, 4.6, 2771, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570464, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexyol0512hx5ep8sdovbf', 'Kasim Palsu Penguasa Istana', 'Bara, karyawan yang terlempar ke masa kerajaan, terpaksa pura-pura jadi kasim. Berkat kecerdikan, dia lolos pemeriksaan dan ikut selir. Sambil menavigasi intrik istana, dia diam-diam berlatih bela diri, naik pangkat, melawan kepala kasim, menggagalkan siasat Permaisuri, memecah formasi, dan menumpas pemberontakan.', 'https://stream.shortlovers.id/melolo/kasim-palsu-penguasa-istana/cover.jpg', NULL, '["Serangan balik","Pemeran Utama Pria","Imajinasi Pria","Drama Sejarah","Kekuatan super"]', '[]', 88, 4.8, 827, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570464, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexyx3055zhx5epvrxhpk1', 'Kau adalah Cahaya Hidupku', 'Di malam bersalju, Cindy dibuang di pemakaman. Di sana, ia bertemu dengan Melvin, dan mereka menemukan harapan dalam diri masing-masing. Presdir Melvin memberinya rumah yang hangat, membantunya menemukan kembali keluarganya, dan mengungkap misteri asal-usulnya. Kisah mereka dipenuhi momen manis dan saling menyembuhkan.', 'https://stream.shortlovers.id/melolo/kau-adalah-cahaya-hidupku/cover.webp', NULL, '["Drama","Bisnis","Keluarga","Misteri","Balas Dendam"]', '[]', 75, 4.8, 2931, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570465, 1771180926);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexzju05a6hx5eiyc5w75c', 'Kaya Raya di Era 1992', 'Ketika terlahir kembali ke tahun 1992, Rizky Pratama bertekad menebus dosa masa lalu. Dengan bekal pengetahuan dari masa depan, dia memulai usaha dari barang rongsok, menghadapi musuh, membangun bisnis, dan berusaha mendapatkan kembali kepercayaan istri serta anaknya.', 'https://stream.shortlovers.id/melolo/kaya-raya-di-era-1992/cover.jpg', NULL, '["Kelahiran kembali","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik"]', '[]', 85, 4.6, 5049, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570465, 1770977040);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleexzza05exhx5eix859a8s', 'Kegagalan dan Kerajaan Bisnisku', 'Setelah bereinkarnasi dan kembali ke masa lalu, Hardy bertekad untuk menebus kegagalannya di kehidupan sebelumnya. Dia memanfaatkan pengetahuan tentang masa depan untuk mengumpulkan modal dengan cepat. Kemudian, dia mulai merambah ke berbagai bidang bisnis, dan secara bertahap membangun kerajaan bisnisnya.', 'https://stream.shortlovers.id/melolo/kegagalan-dan-kerajaan-bisnisku/cover.jpg', NULL, '["Harem","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik","Kelahiran kembali"]', '[]', 100, 4.6, 2052, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570466, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey0lp05kihx5e9ajunwzu', 'Kekasihku, Pengawalku', 'Santo, seorang satpam biasa, tidak sengaja menyinggung putri konglomerat. Sejak itu, dia terus diselidiki dan dibayangi para putra konglomerat lain yang cumburu. Jika begini terus, Santo khawatir identitasnya akan terbongkar.', 'https://stream.shortlovers.id/melolo/kekasihku-pengawalku/cover.jpg', NULL, '["Bukan siapa-siapa","Serangan balik","Pemeran Utama Pria","Fantasi perkotaan","Tak terkalahkan"]', '[]', 77, 4.9, 659, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570467, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey0wh05othx5eevhrtkzl', 'Kembali Pulang', 'Andi menyesal sudah mencoba bunuh diri di tepi sungai. Dia justru terlempar ke 1979, bertemu lagi dengan istrinya, Rahma, dan putrinya, Nia. Ia bertekad menebus kesalahan dan memperbaiki nasib keluarga. Ia berburu, jual ginseng, sambil menghadapi prasangka kerabat dan warga, hingga akhirnya meraih kebahagiaan.', 'https://stream.shortlovers.id/melolo/kembali-pulang/cover.jpg', NULL, '["Kelahiran kembali","Pemeran Utama Pria","Imajinasi Perkotaan","Serangan balik","Desa"]', '[]', 78, 4, 3897, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570467, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey18t05t6hx5esdb4j90m', 'Kultivator Kuno di Era Digital', 'Setelah 10.000 tahun berlatih di dunia dewa, Alex kembali ke dunia modern tapi kemampuannya tidak sengaja terungkap lewat siaran adiknya. Aksinya, dari meracik pil hingga menyembuhkan luka membuatnya viral, memicu kebangkitan energi spiritual dan menarik perhatian keluarga-keluarga besar.', 'https://stream.shortlovers.id/melolo/kultivator-kuno-di-era-digital/cover.jpg', NULL, '["Kembali","Pemeran Utama Pria","Fantasi perkotaan","Serangan balik","Keluarga"]', '[]', 79, 4.5, 3512, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570468, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey1hd05xlhx5ezpuaaqyu', 'Lahir Kembali Untuk Sukses', 'Yani Santoso bangkrut karena dikhianati rekan bisnis dan mengakhiri hidupnya. Ia terlahir kembali sepuluh tahun sebelumnya. Menyadari kesalahan terhadap keluarga, ia bertekad menebusnya dan memanfaatkan pengetahuan masa lalu untuk membangun bisnis baru.', 'https://stream.shortlovers.id/melolo/lahir-kembali-untuk-sukses/cover.jpg', NULL, '["Kelahiran kembali","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik"]', '[]', 80, 4.9, 707, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570468, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey1t70622hx5eskusjzp9', 'Levelku 9999, Tetua Baru 100', 'Terdampar di Gunung Mega sepuluh tahun, Bagus Santosa dapat kemampuan luar biasa dari Sistem Sakti tapi tak tahu cara berlatih. Dijuluki “Orang Sakti Serba Bisa”, ia disangka sesepuh legendaris. Lewat kesalahpahaman, ia tunjukkan kekuatan, kalahkan Lembaga Hitam dan sakti, hingga jadi terkuat di dunia.', 'https://stream.shortlovers.id/melolo/levelku-9999-tetua-baru-100/cover.jpg', NULL, '["Serangan balik","Pemeran Utama Pria","Imajinasi Pria","Sistem","Time Travel"]', '[]', 76, 4.1, 2286, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570468, 1770710073);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey1zy066bhx5e287hdfzm', 'Luka Masa Lalu', 'Dihina dan dikhianati, Zaki bangkit dari kematian lima tahun lalu. Dia membongkar kebusukan keluarga Servan, membalas dendam atas kematian ayah angkat dan kekasihnya. Lewat lagu-lagu emas dan siaran langsung, Zaki menuntut keadilan dan meraih hidup baru bersama orang-orang yang dia cintai.', 'https://stream.shortlovers.id/melolo/luka-masa-lalu/cover.jpg', NULL, '["Kelahiran kembali","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik","Keluarga"]', '[]', 70, 4.8, 3126, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570469, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey27l06a8hx5erk4azpc7', 'Mantan Dikejar Pacar Imut', 'Setelah terlahir kembali, Rizky Surya berhenti mengejar Putri Ayu dan justru dikejar oleh Nadia Pratama yang pernah ia tolong. Kisah cinta mereka berkembang, Rizky sukses membuktikan diri, meraih karier dan cinta sekaligus. Mereka akhirnya menikah dan punya anak, sementara Putri Ayu hanya bisa menyesali keputusannya.', 'https://stream.shortlovers.id/melolo/mantan-dikejar-pacar-imut/cover.jpg', NULL, '["Kelahiran kembali","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik"]', '[]', 79, 4.2, 2973, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570469, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey2in06enhx5ex8wbi2x9', 'Mata Pengubah Nasib', 'Rizal, seorang mahasiswa streamer yang melakukan tantangan berburu barang antik, secara mengejutkan memperoleh kemampuan "mata tembus pandang". Berkat hal itu, kehidupannya langsung melesat naik.', 'https://stream.shortlovers.id/melolo/mata-pengubah-nasib/cover.jpg', NULL, '["Harem","Pemeran Utama Pria","Imajinasi Perkotaan","Serangan balik","Kekuatan super"]', '[]', 80, 4.1, 1612, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570469, 1770759595);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey2tt06j4hx5el2zj9q71', 'Mata Tembus Pandang', 'Hidup miskin bersama kakak iparnya membuat Andi Saputra putus asa. Suatu hari, pertemuan dia dengan seorang kakek misterius memberinya “Mata Tembus Pandang” yang bisa melihat segalanya. Sejak saat itu, hidupnya berubah drastis menjadi kaya dan berkuasa. Dia bertekad membahagiakan sang kakak ipar.', 'https://stream.shortlovers.id/melolo/mata-tembus-pandang/cover.jpg', NULL, '["Bukan siapa-siapa","Kekuatan super","Pemeran Utama Pria","Imajinasi Perkotaan"]', '[]', 87, 4.7, 4591, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570470, 1770834200);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey31w06nzhx5ea29rueba', 'Mau Cerai,Masih Cinta', 'Adi dan istrinya cerai karena hubungan tidak jelas Sindy dan Rafael, adik angkatnya. Dia bahkan didorong dan hampir mati. Sindy yang menyesal ingin memperbaiki hubungan mereka, namun hati Adi sudah dingin. Dia mau para pengkhianat membayar harga atas perbuatannya.', 'https://stream.shortlovers.id/melolo/mau-ceraimasih-cinta/cover.jpg', NULL, '["Kelahiran kembali","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik"]', '[]', 80, 4.5, 1052, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570470, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey39306sghx5e8q4t0nim', 'Memperbaiki Masa Lalu', 'Di kehidupan sebelumnya, Yohan menikahi Melly, gadis idamannya. Akan tetapi, Melly mengkhianatinya. Yohan mengalami kecelakaan dan terlahir kembali di ruang ujian masuk kuliah. Kali ini, dia akan melepaskan Melly dan mengutamakan uang. Dia tidak sengaja bertemu dan menjalin hubungan dengan Jenny dan membuat Melly sangat menyesal.', 'https://stream.shortlovers.id/melolo/memperbaiki-masa-lalu/cover.jpg', NULL, '["Tycoon","Kelahiran kembali","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik"]', '[]', 88, 4, 1308, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570470, 1770637803);
