INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey4te07aehx5emtgpji4o', 'Penantian Cinta Sang Suami', 'Rizky Pratama tiba-tiba terbangun di tubuh suami Direktur Utama Putri Ayu. Awalnya ia berharap hidup nyaman, namun ternyata ia harus menghadapi reputasi buruk: kecanduan judi, pencurian, dan perselingkuhan dengan Intan Permata. Saat Putri Ayu ingin bercerai, Rizky membuktikan ketulusannya, menolak perceraian dan mengusir Intan.', 'https://stream.shortlovers.id/melolo/penantian-cinta-sang-suami/cover.jpg', NULL, '["Serangan balik","Pemeran Utama Pria","Kehidupan perkotaan","Time Travel"]', '[]', 60, 4.7, 1951, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570472, 1770637803);
