INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey5hp07i8hx5enzetzru2', 'Penglihat Abadi', 'Rendy mewarisi Mata Dewa Ilahi dari kakeknya, memberi kemampuan melihat masa lalu dan masa depan. Ia menolong Maya, membuka rahasia makam, dan bersinar di lelang. Meski dikhianati, ia meraih kekuatan dan sekutu, menghadapi ancaman, membalas dendam, dan akhirnya hidup bahagia dengannya.', 'https://stream.shortlovers.id/melolo/penglihat-abadi/cover.jpg', NULL, '["Bukan siapa-siapa","Serangan balik","Pemeran Utama Pria","Imajinasi Perkotaan","Lainnya"]', '[]', 79, 4.9, 1788, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570473, 1770692548);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey5od07mnhx5e9pw6wxv4', 'Penglihatan Ilahi', 'Nasib Christian Lesmana, pengantar makanan, berubah total saat darahnya membangkitkan mata dewa. Dengan kemampuan itu, ia ubah barang murah jadi harta miliaran, kejutkan ahli, menang kompetisi, hadapi tantangan, dan temukan cinta. Inilah kisah transformasi legendarisnya.', 'https://stream.shortlovers.id/melolo/penglihatan-ilahi/cover.jpg', NULL, '["Serangan balik","Pemeran Utama Pria","Imajinasi Perkotaan","Lainnya","Kekuatan super"]', '[]', 100, 4.3, 3318, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570473, 1770851042);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey5xh07s8hx5egs1jv254', 'Penyesalan Mantan Tunangan', 'Rizky Pratama menyembunyikan identitasnya saat membangun Lestari Group bersama Indah Lestari. Menjelang pernikahan, pengkhianatan Indah dan Dimas membuatnya pergi. Saat Lestari Group terancam, Indah menyadari pentingnya Rizky, namun hatinya telah terpaut pada cinta baru.', 'https://stream.shortlovers.id/melolo/penyesalan-mantan-tunangan/cover.jpg', NULL, '["Identitas Tersembunyi","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik","Drama Kantor"]', '[]', 60, 4.9, 1970, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570474, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey66v07vlhx5eqh77w5ox', 'Pewaris Konglomerat Dihina Mantan', 'Rizky Pratama, pekerja konstruksi yang sederhana, tiba-tiba mewarisi kekayaan triliunan dari keluarganya. Namun, sebelum ia menikmati hidup barunya, tunangannya Citra Dewi meninggalkannya demi pria kaya lain. Ditinggal dan dikhianati, Rizky harus bangkit hadapi tantangan dan buktikan dirinya di dunia baru yang penuh persaingan.', 'https://stream.shortlovers.id/melolo/pewaris-konglomerat-dihina-mantan/cover.jpg', NULL, '["Tycoon","Serangan balik","Pemeran Utama Pria","Kehidupan perkotaan","Bukan siapa-siapa"]', '[]', 98, 4.7, 5250, 1, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570474, 1771142064);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey6ic0812hx5edxb739pa', 'Putus Cinta, Dunia Memihakku', 'Usai hubungan enam tahunnya kandas, Rodi nekat menikah kilat dengan seorang wanita cantik. Niatnya hanya ingin hidup tenang, tetapi keberuntungan datang bertubi-tubi. Mulai dari sewa apartemen mewah dua juta, menang undian mobil Fermari, hingga investor berebut ingin bekerja sama dengannya.', 'https://stream.shortlovers.id/melolo/putus-cinta-dunia-memihakku/cover.webp', NULL, '["Romantis"]', '[]', 84, 4.9, 1173, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570474, 1771119979);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey6pv085rhx5e39u8hdgm', 'Rahasia di Balik Kedai Pangsit', 'Damar menikmati hidup sederhana dengan kedai pangsit kecilnya. Setiap hari hanya berjualan, mengobrol, dan menutup toko sesuka hati. Putranya, Aditya, merasa heran mengapa ayahnya tetap membuka kedai meski sudah tajir. Damar hanya tersenyum dan berkata, satu pangsit ini tidak bisa dibeli dengan uang seberapa pun.', 'https://stream.shortlovers.id/melolo/rahasia-di-balik-kedai-pangsit/cover.jpg', NULL, '["Tycoon","Identitas Tersembunyi","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik"]', '[]', 63, 4.3, 1471, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570475, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey6wh089ahx5e79htt7td', 'Reinkarnasi Sang Konglomerat', 'Fajar Lingga, sang raja bisnis tewas diracuni kekasih gelapnya, Windi. Namun, dia terlahir kembali sebagai dirinya 30 tahun lalu, tepat di hari tragedi istri dan putrinya bunuh diri karena tekanan hidup dan keputusasaan yang dia perbuat. Fajar pun bertekad untuk perbaiki semua kesalahannya.', 'https://stream.shortlovers.id/melolo/reinkarnasi-sang-konglomerat/cover.jpg', NULL, '["Kelahiran kembali","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik","Keluarga"]', '[]', 84, 4.4, 2094, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570475, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey7es08i0hx5eqcbqyy4r', 'Saat Mantan Memohon Kembali', 'Arga menikahi Nayla demi cinta, tapi setelah 7 tahun berkorban, putranya malah meminta ayah baru. Kecewa, Arga bercerai dan sukses besar. Saat putrinya mencarikan ibu baru, Nayla justru memohon rujuk.', 'https://stream.shortlovers.id/melolo/saat-mantan-memohon-kembali/cover.jpg', NULL, '["Menantu Pria","Identitas Tersembunyi","Kehidupan perkotaan","Tycoon","Serangan balik"]', '[]', 80, 4.7, 4465, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570476, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey7uw08mhhx5egbzar7gu', 'Salah Nyatakan Cinta', 'Surya programmer di Grup Jaya, tak sengaja terikat sistem evolusi. Karena, salah kirim pesan ke Yuli bosnya, mereka pun mulai terikat. Kemampuan sistem, membuat Surya menonjol di Perusahaan. Mereka juga nikah kontrak, bertemu keluarga, hingga akhirnya, mendapatkan kesuksesan dalam karier dan cinta.', 'https://stream.shortlovers.id/melolo/salah-nyatakan-cinta/cover.jpg', NULL, '["Bukan siapa-siapa","Serangan balik","Pemeran Utama Pria","Imajinasi Perkotaan","Sistem"]', '[]', 79, 4, 1198, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570476, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey82e08qwhx5ejihpycs7', 'Sang Dewa Judi', 'Dewa Judi Awin Lintang yang tewas tragis terlahir kembali sebagai Yanto Surya di Bintaro. Mengetahui putranya dijebak dalam permainan kartu, ia turun tangan demi menyelamatkannya.', 'https://stream.shortlovers.id/melolo/sang-dewa-judi/cover.jpg', NULL, '["Duda","Kelahiran kembali","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik"]', '[]', 94, 4.3, 4374, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570477, 1770637803);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey8c708w5hx5et405w3iv', 'Sang Master Turun Gunung', 'Rian Mukti, hidup bersama kakek dengan mengais sampah, tiba-tiba menerima perjodohan dari keluarga kaya setelah kakeknya meninggal. Dibawa ke Gunung Agung untuk belajar seni bela diri, ia kembali setelah 13 tahun dengan niat membatalkan perjodohan tersebut.', 'https://stream.shortlovers.id/melolo/sang-master-turun-gunung/cover.webp', NULL, '["Drama","Aksi","Bisnis","Keluarga"]', '[]', 66, 4.8, 5085, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570477, 1771241166);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey8ii08zuhx5eekjsvhod', 'Satpam Jadi Suami Bos', 'Aditya yang sudah pensiun menikmati hidup tenang, tapi tiba-tiba diminta anaknya, Rizky, bekerja sebagai satpam. Tak disangka, Aditya justru bertemu dan jatuh hati pada Citra, sang direktur cantik, hingga akhirnya mereka menikah dan Citra menjadi ibu tiri bagi Rizky. Kisah penuh kejutan, humor, dan kehangatan keluarga.', 'https://stream.shortlovers.id/melolo/satpam-jadi-suami-bos/cover.jpg', NULL, '["Bukan siapa-siapa","Identitas Tersembunyi","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik"]', '[]', 69, 4.7, 3203, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570477, 1770641817);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey8p5093phx5ev2pwjq39', 'Sekali Lihat, Jadi Sultan', 'Sebuah kemampuan misterius mengubah hidup Riky Hidayat. Dengan Mata Penilai, ia mengungkap harta tersembunyi dan kebohongan dunia barang antik. Namun semakin tinggi ia melangkah, makin berbahaya permainan yang harus dihadapinya.', 'https://stream.shortlovers.id/melolo/sekali-lihat-jadi-sultan/cover.webp', NULL, '["Drama","Misteri"]', '[]', 80, 4.5, 4714, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570477, 1771180926);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleey8wk0986hx5ewrp83p3m', 'Sesepuh Tertua yang Masih Muda', 'Titus Liton, orang hebat dari Dunia Peri, menghancurkan kultivasinya dan berkultivasi ulang di dunia kecil. Dia diselamatkan oleh Keluarga Liton setelah naga hitam pelindungnya kabur, tetapi dianggap sebagai orang bodoh karena ingatannya belum pulih.', 'https://stream.shortlovers.id/melolo/sesepuh-tertua-yang-masih-muda/cover.webp', NULL, '["Drama","Fantasi","Keluarga"]', '[]', 91, 4.4, 4861, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770570478, 1771219216);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlegdojc05903etxrdzb9por', 'Kaya dari Memanggil Leluhur Dewasa', 'Luna Sinari, pekerja biasa, berdoa ke lukisan leluhur Raja Aldo lalu buka jalur waktu ke Kerajaan Aldoria. Tukar mi instan, jaket bulu dengan perak, bantu Raja Aldo menang Perang Suksesi, dapat emas dan permata. Dari miskin jadi kaya berkat leluhur dewasa！', 'https://stream.shortlovers.id/melolo/kaya-dari-memanggil-leluhur-dewasa/poster.jpg', NULL, '["Fantasi","Bisnis"]', '[]', 137, 4.9, 2974, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770572877, 1770931790);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlegdpgk05ld3etxkgpx39ge', 'Kebangkitan Dewi Giok', 'Dewi Permata, gadis desa yang dihina dan ditinggal pacarnya, tersambar petir dan mendapat kemampuan tembus pandang dari gelang neneknya. Ia masuk dunia judi giok, sukses beruntun, menggagalkan intrik, memimpin Lino Gold dan Asosiasi Giok, lalu meraih Giok Hijau Imperial.', 'https://stream.shortlovers.id/melolo/kebangkitan-dewi-giok/poster.jpg', NULL, '["Aksi","Fantasi"]', '[]', 123, 4.5, 5221, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770572879, 1771023578);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleqwcmy04rgdr83jsiyxb73', 'Kaisar Naga Seluruh Ajaran', 'Raden hidup susah sejak ayahnya hilang. Ia berlatih keras, namun nadinya dirampas orang jahat. Berkat giok ayahnya, ia membentuk Nadi Sembilan Naga, membalas penghinaan dan menang lomba. Setelah tahu ayahnya di Sekte Pedang Sepuluh Arah, ia memulai perjalanan mencari ayahnya dan bertemu teman baru.', 'https://stream.shortlovers.id/melolo/kaisar-naga-seluruh-ajaran/poster.jpg', NULL, '["Drama","Fantasi","Keluarga","Balas Dendam"]', '[]', 141, 4.8, 3521, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770590545, 1771180926);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleqwfiy05t7dr83rf2s5xv8', 'Kebangkitan Dewa Pedang', 'Setelah keluarganya hancur akibat pengkhianatan, Raka Pratama diselamatkan Surya Wijaya dan berlatih di Desa Makmur Abadi. Delapan tahun kemudian, ia bergabung dengan Sekte Pedang Nusantara, memulai perjalanan mengungkap jati diri dan rahasia besar antara Dewa Dunia Atas dan Dunia Roh Manusia.', 'https://stream.shortlovers.id/melolo/kebangkitan-dewa-pedang/poster.jpg', NULL, '["Aksi","Fantasi"]', '[]', 123, 4.7, 5297, 2, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770590548, 1771243052);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleqwihr06svdr83h13nvraa', 'Kepala Desa Pembawa Kemakmuran', 'Pak Arif terlahir kembali sebagai Lurah Desa Mekar Jaya sepuluh tahun lalu. Berbekal Sistem Pembangunan Desa, ia memimpin warga berinovasi, mengatasi kemiskinan, dan mengubah desa termiskin menjadi desa paling makmur di negeri. Perjuangan dan kerja sama membawa harapan baru bagi seluruh desa.', 'https://stream.shortlovers.id/melolo/kepala-desa-pembawa-kemakmuran/poster.jpg', NULL, '["Kehidupan"]', '[]', 142, 4.7, 3941, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770590552, 1770931795);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleqwjkr073cdr83wniid2l8', 'Lahir Kembali, Jadi Raja Hutan', 'Rizky Pratama terlahir kembali di masa sulit, bertekad merebut kembali hidupnya. Ia mulai menjual hasil alam desa untuk mengatasi krisis keuangan, namun sempat diragukan warga. Berkat dukungan Dewi Syaiful dan bukti dari Koperasi Desa, Rizky akhirnya dipercaya. Bersama warga, ia memulai perjalanan menuju kemakmuran desa.', 'https://stream.shortlovers.id/melolo/lahir-kembali-jadi-raja-hutan/poster.jpg', NULL, '["Fantasi"]', '[]', 110, 4.1, 3922, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770590554, 1770931797);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleqwkah07c7dr836o3wamy7', 'Lelaki Bermata Dewa', 'Yulian Wijaya, magang di balai lelang, tak sengaja merusak barang antik dan malah mewarisi kekuatan Mata Langit. Kekuatan yang bisa menembus apa pun, menilai barang, dan menyembuhkan. Niat awalnya hanya cari uang dan jodoh, tapi kekuatannya justru membawanya pada takdir mengubah dunia.', 'https://stream.shortlovers.id/melolo/lelaki-bermata-dewa/poster.jpg', NULL, '["Fantasi"]', '[]', 136, 4.9, 3117, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770590554, 1770931798);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleqwm0z07wadr83qclx9p90', 'Mata Ajaib di Pasar Barang Antik', 'Pak Hadi tiba-tiba mendapat kemampuan melihat tembus pandang setelah kecelakaan. Dengan kekuatan ini, ia bisa menilai nilai barang antik secara akurat. Berbekal bakat uniknya, Pak Hadi sukses menemukan harta karun di pasar barang antik, membangun bisnis sendiri, dan perlahan naik dari orang biasa menjadi miliarder.', 'https://stream.shortlovers.id/melolo/mata-ajaib-di-pasar-barang-antik/poster.jpg', NULL, '["Fantasi"]', '[]', 130, 4, 3619, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770590557, 1770931801);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleqwnhe08gwdr83gewvh8ap', 'Mata Sakti Mengungkap Rahasia', 'Yansen menderita penyakit mematikan. Sebelum meninggal, dia ingin memanfaatkan sisa hidupnya dengan menjual kornea matanya dan memberikan uang terakhir pada istrinya. Namun, dia malah mengalami pengkhianatan dari istrinya yang berselingkuh. Karena kejadian itu, Yansen juga mengalami kecelakaan lalu lintas, tetapi secara tak terduga dia mendapatkan kemampuan mata sakti dan memulai kehidupan yang penuh keberuntungan.', 'https://stream.shortlovers.id/melolo/mata-sakti-mengungkap-rahasia/poster.jpg', NULL, '["Misteri","Fantasi"]', '[]', 119, 4.5, 4140, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770590559, 1770931802);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleqwoxo091pdr83z0ojjp7q', 'Menyesali Batalnya Pernikahan', 'Efendi sejak kecil terpisah dari keluarga Susilo dan dibesarkan oleh ibu angkatnya. Dia bercita-cita membalas budi pada ibu angkatnya setelah dewasa. Namun, pada hari pernikahannya, calon istrinya malah menolak kehadiran ibu angkat dan adik perempuannya, bahkan memaksa Efendi untuk memutuskan hubungan dengan keluarganya. Karena hal ini, Efendi memutuskan untuk membatalkan pernikahan. Tak disangka, dia justru menemukan bahwa dirinya adalah pewaris sah keluarga Susilo.', 'https://stream.shortlovers.id/melolo/menyesali-batalnya-pernikahan/poster.jpg', NULL, '["Romantis","Balas Dendam"]', '[]', 110, 4.5, 3947, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770590560, 1770931806);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleqwr0709lpdr836dys5ui2', 'Palu Ajaib Pengubah Segalanya', 'Andi Pratama tak sengaja mendapatkan Palu Sakti dari Dewa Sungai, artefak yang mampu mengubah benda biasa menjadi luar biasa, besi tua jadi emas, obat biasa jadi ramuan ajaib. Dengan kekuatan itu, Andi bangkit dari keterpurukan, membantu orang-orang di sekitarnya, dan membangun kerajaan bisnis bernilai triliunan.', 'https://stream.shortlovers.id/melolo/palu-ajaib-pengubah-segalanya/cover.webp', NULL, '["Fantasi"]', '[]', 109, 4.4, 4069, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770590563, 1771049972);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleuaqqu09hf5bazf2788ykc', 'Nona Riley Beraksi', 'Demi mewarisi bisnis keluarga, Ayah Riley mengubur putrinya hidup-hidup. Namun, Riley tidak meninggal. Dia diselamatkan oleh tujuh orang hebat. Bertahun-tahun kemudian, Riley pergi menghentikan Welly, si pria sombong yang bertunangan dengannya sejak kecil untuk tidak menikahi orang lain. Pada saat yang sama, ayah Riley serta putri haramnya terus mempersulit Riley. Setelah Riley menghentikan pernikahan Welly, keduanya jatuh cinta seiring berjalannya waktu. Setelah mengatasi berbagai kesulitan, mereka akhirnya menikah.', 'https://stream.shortlovers.id/melolo/nona-riley-beraksi/poster.jpg', NULL, '["Drama","Romantis","Aksi","Bisnis","Keluarga"]', '[]', 149, 4.2, 4929, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770596255, 1771180926);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleuatgs0apm5baz7icx1ave', 'Perjalanan Naga Muda', 'Leon pindah ke Kota Zenus dari ibu kota bersama orang tuanya. Dia ingin hidup damai, tapi siapa sangka keluarganya malah dibunuh oleh musuh mereka. Leon yang beruntung bisa kabur dari peristiwa itu dan diangkat oleh Dewa Naga dari Kuil Naga untuk dilatih di Gunung Ludas.', 'https://stream.shortlovers.id/melolo/perjalanan-naga-muda/poster.jpg', NULL, '["Drama","Fantasi","Keluarga"]', '[]', 112, 4.8, 3331, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770596258, 1771180926);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleuau2c0b195bazkauj4nxe', 'Pulang Kampung Bawa CEO', 'Andre, anak rantau yang lelah jadi budak korporat, tiba-tiba punya sistem ajaib. Andre pun langsung berhenti kerja dan pulang kampung untuk merintis usaha. Anna, atasan Andre yang kaya raya dan jenuh dengan kehidupan perkotaan, memutuskan ikut Andre ke kampung. Bagaimana kelanjutan kisah mereka?', 'https://stream.shortlovers.id/melolo/pulang-kampung-bawa-ceo/cover.jpg', NULL, '["Bisnis","Kehidupan"]', '[]', 110, 4.7, 3278, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770596259, 1770931817);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmleuaxus0cww5baz7jaso25k', 'Sistem Harta Tersembunyi', 'Setelah menganggur dan pulang ke desa, Nanda Saputra memperoleh sistem pencari harta karun yang membuat setiap galiannya menghasilkan benda langka, bahkan seekor bayi naga. Dengan harta tak berujung di pegunungan, hidupnya berubah drastis.', 'https://stream.shortlovers.id/melolo/sistem-harta-tersembunyi/cover.jpg', NULL, '["Misteri","Bisnis"]', '[]', 111, 4.6, 4501, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770596264, 1770931828);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlf4y9dj0bk0z4nj5lk668d4', 'Ruang Sistem Putri Jenderal', 'Nia Sari, tewas tertimpa barang dan reinkarnasi ke tubuh putri sulung jenderal yang bucin. Hal pertama yang dilihatnya saat membuka mata adalah seluruh keluarganya hampir dipenggal. Dengan ruang sistem, dia menentang takdir dengan setengah potong roti. Hukuman mereka pun diganti menjadi pengasingan.', 'https://stream.shortlovers.id/melolo/ruang-sistem-putri-jenderal/cover.jpg', NULL, '["Pemeran Utama Wanita Kuat","Kelahiran kembali","Romansa","Periode Romantis","Serangan balik"]', '[]', 72, 4.6, 1745, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770614148, 1770837003);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlf4ybyg0cj3z4nj7ixggwor', 'Setelah Bertapa, Kutaklukkan Dunia', 'Guru: “Kamu kuutus berlatih ke dunia, malah dapat banyak harta dan menggoda wanita. Kalau bablas, gimana?”Murid: “Usaha jadi warisan, harta bisa disumbang.”Guru: “Lalu wanita-wanita itu?”Murid: “Walau banyak yang cinta aku, yang kucinta hanya satu.”Guru: “Satu tetap repot. Nanti, kamu mau jadi dewa atau menikah?”Murid: “Aku…”', 'https://stream.shortlovers.id/melolo/setelah-bertapa-kutaklukkan-dunia/poster.webp', NULL, '["Fantasi"]', '[]', 161, 4.8, 1530, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770614152, 1770931827);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlf4yckv0cwwz4njopraojki', 'Siapa yang Sedang Membicarakan Kaisar', 'Anjani, mahasiswi yang terlempar ke masa lalu, jadi pelayan istana. Karena bisa dengar pikiran kaisar, ia diangkat jadi pelayan pribadinya. Ia temukan kaisar punya kepribadian ganda: satu licik, satu polos tapi kejam. Dengan keahlian masak, Anjani taklukkan hati kaisar. Dalam istana， melalui bergaul, dia perlahan-lahan jatuh cinta pada kaisar.', 'https://stream.shortlovers.id/melolo/siapa-yang-sedang-membicarakan-kaisar/poster.webp', NULL, '["Drama","Romantis"]', '[]', 119, 4, 3430, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770614152, 1771180926);
