INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlficdnn00fjldfkvtagzmfu', 'Cinta Sang Komandan', 'Mia Susanto dan Ferry Santo, sang komandan markas militer, memilih menikah diam-diam. Meski status mereka rahasia, Mia terus dihantui kejahatan Ingrid Hartono yang cemburu, namun selalu berhasil lolos. Bakat medis dan masa lalu Mia pun terungkap, hingga konspirasi Ingrid terbongkar. Akhirnya, Ferry yang dingin itu mengejutkan semua orang dengan melamar Mia secara terbuka, mengakhiri pernikahan rahasia mereka dengan cinta.', 'https://stream.shortlovers.id/melolo/cinta-sang-komandan/poster.webp', NULL, '["Romantis"]', '[]', 130, 0, 1, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770636642, 1770931768);
