INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlficduk0140ldfkp81gpu58', 'Istri Desa Si Kapten', 'Raina Yuni, gadis desa pencinta tanam-menanam, menikah kilat dengan satpam bandara karena desakan orangtua. Setelah menikah, ia baru sadar salah orang gara-gara wajah mirip. Namun, suami yang salah ini justru membawa keberuntungan—usaha taninya sukses dan ia dikaruniai anak kembar genius. Sampai akhirnya, sang mantan kekasih datang dan membongkar identitas asli suaminya: mantan kapten pilot dan pewaris keluarga konglomerat.', 'https://stream.shortlovers.id/melolo/istri-desa-si-kapten/poster.webp', NULL, '["Romantis","Kehidupan"]', '[]', 150, 0, 0, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770636642, 1770931787);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlficdv20187ldfkfefzusk1', 'Istri Kesayangan Galak', 'Livy Sutomo, putri Keluarga Sutomo yang hilang sejak kecil digantikan oleh Susi Sutomo, putri ayah dan ibu angkatnya, karena identitas Livy. Setelah selamat dari kematian, Livy memutuskan untuk mengambil kembali semua miliknya. Pada saat yang sama, Livy dan Jimy Kadir, aktor film terkenal, saling menyukai.', 'https://stream.shortlovers.id/melolo/istri-kesayangan-galak/poster.webp', NULL, '["Romantis"]', '[]', 126, 0, 1, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770636642, 1770931787);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlficdw501f0ldfkgyyj0ysu', 'Pacari Musuh Mantan Istri', 'Reza kembali ke masa dia diceraikan oleh istrinya, Kelly Stanley, yang memilih cinta pertamanya. Reza pun dengan lapang dada melepaskannya. Tidak disangka Kelly menyesal melepaskan Reza.Lalu, dia kembali mengejar Reza. Namun, ternyata Reza sudah berpacaran dengan musuh besarnya, Tania Sadikin. - Drama series', 'https://stream.shortlovers.id/melolo/pacari-musuh-mantan-istri/cover.jpg', NULL, '["Harem","Pemeran Utama Pria","Kehidupan perkotaan","Serangan balik","Kelahiran kembali"]', '[]', 73, 0, 5, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770636642, 1770670853);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlficdxp01h2ldfkddawznbo', 'Tangan Kiri Sakti Kuli Tambang', 'Setelah menemukan sebuah batu giok, tangan kiri Yoka menjadi sakti, yaitu bisa menilai kualitas giok dengan sentuhan. Sejak itu, Yoka yang dulunya kuli tambang banting setir menjadi pedagang giok. Ayo saksikan perjalanan Yoka berburu giok langka dan menjadi sukses.', 'https://stream.shortlovers.id/melolo/tangan-kiri-sakti-kuli-tambang/cover.jpg', NULL, '["Fantasi"]', '[]', 119, 0, 4, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770636642, 1770931831);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlficdy601keldfk8eu8htm3', 'Vila Portal Dunia Lain', 'Ratna Dewi mewarisi vila berutang dan menemukan pintu waktu penghubung dua dunia. Ia membawa bahan unik dari dunia lain untuk berjualan sarapan yang laris. Di dunia asal, ia naik pangkat menjadi dewi dengan tanah luas dan banyak pengikut. Petualangan lintas dunia ini mengubah hidupnya menuju kesuksesan luar biasa.', 'https://stream.shortlovers.id/melolo/vila-portal-dunia-lain/cover.jpg', NULL, '["Fantasi"]', '[]', 127, 0, 4, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770636642, 1770931834);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlg9tn3t0000w04uxcov58iq', 'Romansa Setelah Pernikahan', 'Ezio Ford is Jade Wynn''s boss. They accidentally connect through a one-night stand, and coincidentally, the Fords'' destiny ring ends up in Jade''s hands. They sign a marriage agreement and become contract spouses. Then the wooden turtle sculpture reveals a past event: Sixteen-year-old Ezio was once saved by Jade, but Olivia Donne impersonated her and stole Ezio''s love. This complicates their relationship. Despite Ezio deciding to continue his relationship with Olivia and compensate Jade, things spiral out of control. Olivia senses the threat, exposes the truth, and schemes to drive Jade away. Only then does Ezio realize his true feelings, but Jade has already disappeared.


Ezio Ford adalah bos di tempat Jade bekerja. Mereka secara tidak sengaja berhubungan satu malam dan secara kebetulan, cincin takdir Keluarga Ford berakhir di tangan Jade. Mereka menandatangani perjanjian pernikahan dan menjadi pasangan kontrak. Kemudian patung kura-kura kayu tersebut mengungkap peristiwa masa lalu: Ezio yang berusia 16 tahun pernah diselamatkan oleh Jade, tetapi Olivia berbohong sebagai penyelamat Ezio dan mencuri cinta Ezio. Hal ini membuat hubungan mereka menjadi rumit. Meskipun Ezio memutuskan untuk melanjutkan hubungannya dengan Olivia dan memberikan kompensasi kepada Jade, segalanya menjadi tidak terkendali. Olivia merasakan ancaman tersebut, mengungkap kebenaran, dan berencana mengusir Jade. Baru saat itulah Ezio menyadari perasaannya yang sebenarnya, tapi Jade sudah menghilang.', 'https://stream.shortlovers.id/melolo/romansa-setelah-pernikahan/cover.jpg', NULL, '["Drama","Romantis","Bisnis","Keluarga"]', '[]', 26, 4.5, 3108, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770682797, 1771184180);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlg9tu28001hw04umzfyenlb', 'Dimanja Habis-habisan oleh Bos', 'Riana dan ibunya hidup di desa. Setelah ibunya meninggal, Riana bekerja di tempat hiburan malam. Tanpa sengaja, dia menjalin hubungan dengan Hardi. Saat berhasil bekerja di perusahaan terkenal, Riana menyadari bahwa Hardi adalah atasannya. Yang membuatnya semakin bingung adalah ternyata dia hamil, dan Hardi sudah tahu hal itu.', 'https://stream.shortlovers.id/melolo/dimanja-habis-habisan-oleh-bos/cover.jpg', NULL, '["Drama","Romantis","Komedi","Bisnis","Keluarga"]', '[]', 102, 4.5, 3588, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770682806, 1771182979);
