INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlggh74y0000ifjli9qjlgp6', 'Putaran Maut yang Tak Berakhir', 'Dewi Ayuningtyas terjebak dalam siklus kematian di hari ulang tahun pernikahannya. Setiap dibunuh, ia bangun kembali pukul enam pagi. Untuk bertahan, Dewi harus mengungkap dalang sebenarnya dan membedakan siapa musuh, siapa sekutu. Setiap kematian membawanya lebih dekat pada kebenaran kelam.', 'https://stream.shortlovers.id/melolo/putaran-maut-yang-tak-berakhir/cover.jpg', NULL, '["Drama","Romantis","Aksi","Misteri","Keluarga"]', '[]', 41, 4.5, 5176, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770693974, 1771243299);
