INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlghvh710000pl5u278d2w1x', 'Si Miskin Dicintai Pengacara', 'Nadia Pramudita, seorang guru TK yang hidup bersama neneknya, tiba-tiba dituduh membunuh sang nenek. Dalam persidangan, ayahnya justru membantu Rizky menjebak Nadia. Arief Pramudita, pengacara ternama, awalnya membela ayah Nadia dan salah menilai kasusnya. Namun, setelah sidang, Arief mulai curiga dan diam-diam melindungi Nadia.', 'https://stream.shortlovers.id/melolo/si-miskin-dicintai-pengacara/cover.jpg', NULL, '["Drama","Romantis","Bisnis","Keluarga"]', '[]', 92, 4.5, 2520, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770696320, 1771184180);
