INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlgx5v0o0000bwwgezdygha6', 'Sisa Cinta di Atas Bara', 'Indira, putri kandung Keluarga Wening, disiksa dan diabaikan sejak ibunya dipaksa mati. Demi balas dendam, dia mendekati tunangan Anita, Aditya Pratama. Aditya akhirnya melihat kebusukan Keluarga Wening, membatalkan pertunangan, dan melindunginya. Indira pun berhasil membalas dendam dan menjadi pasangan Aditya.', 'https://stream.shortlovers.id/melolo/sisa-cinta-di-atas-bara/cover.jpg', NULL, '["Romantis","Keluarga","Drama"]', '[]', 80, 4.5, 3199, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770721998, 1771184180);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlgxx58c0000ukfx6hj4stjp', 'Ayah Kilat Multitalenta', 'Lima tahun lalu, Rara melahirkan anak setelah insiden tak terduga, namun ibu tirinya membohonginya bahwa sang anak telah tiada. Saat dipaksa menikah demi uang, Rara bertemu Seno yang juga ingin menghindari perjodohan. Mereka menikah kilat. Bersama, mereka menghadapi tantangan dan perlahan saling jatuh cinta.', 'https://stream.shortlovers.id/melolo/ayah-kilat-multitalenta/cover.jpg', NULL, '["Romantis","Keluarga","Drama"]', '[]', 73, 4.5, 4472, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770723271, 1771184180);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlgyoud80000lov0qmi5ei1d', 'Legenda Raja Dewa Utara', 'Dikhianati pamannya, Bayu Pratama dipenjara di Penjara Utara. Sepuluh tahun kemudian, ia bangkit sebagai Raja Dewa Utara, menaklukkan Tiga Puluh Enam Negeri dan membentuk organisasi Alam Dewa. Kekuatannya memaksa negeri-negeri tunduk dan meneken damai dengan Negeri Naga. Kisah epik balas dendam dan kebangkitan luar biasa.', 'https://stream.shortlovers.id/melolo/legenda-raja-dewa-utara/cover.webp', NULL, '["Fantasi","Aksi","Dewa Perang","Sakti"]', '[]', 83, 4.5, 5781, 3, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770724564, 1771250713);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlgzxqzf00005kbqtrarytqj', 'Dia yang Tidak Terduga', 'Putri dari keluarga kaya yang bangkrut, terpaksa tunangan sama Kevin Rama demi keluarganya.
Namun, karena campur tangan Fani dan pengkhianatan dari Kevin,
dia tidur dengan seorang pria dewasa yang nggak disangka merupakan paman dari Kevin, Leo Rama.
Nia pun memanfaatkan identitas pria itu untuk balas dendam. Tapi, pria asing ini ternyata adalah cinta sejatinya yang pernah berjanji setia sama dia di masa lalu.', 'https://stream.shortlovers.id/melolo/dia-yang-tidak-terduga/cover.jpg', NULL, '["Keluarga","Bisnis","Drama","Fantasi","Romantis"]', '[]', 100, 4.5, 2859, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770726659, 1771184180);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlh0t8s60000ffdy2t66d785', 'Aroma Cinta Tak Terduga', 'Collin Ferro jatuh cinta pada pandangan pertama kepada Lauryn Johan, dan melakukan segala cara untuk mendapatkan hatinya. Sebagai pebisnis dengan kepribadian dingin, dia tidak pernah tunduk. Tapi dia rela berulang kali merendahkan diri demi Lauryn. Di sela-sela cinta yang membara ini, Lauryn pun menemukan kelembutan. Secercah cinta yang tersembunyi di balik topeng es Collin. Hati Lauryn perlahan-lahan luluh dan terjerat.', 'https://stream.shortlovers.id/melolo/aroma-cinta-tak-terduga/cover.jpg', NULL, '["Bisnis","Romantis","Drama","Misteri"]', '[]', 79, 4.5, 4330, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770728128, 1771184180);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlh1hm5s0000wt52rb9gzfuw', 'Dari Guru Gagal Jadi Legenda', 'Aditya terlempar ke dunia kultivasi dan cuma manusia biasa yang tak bisa berlatih. Saat terpaksa menerima murid, sistem misterius aktif dan setiap kemajuan murid justru memperkuat dirinya. Dari guru asal-asalan, Aditya berubah jadi legenda yang tak terkalahkan.', 'https://stream.shortlovers.id/melolo/dari-guru-gagal-jadi-legenda/cover.jpg', NULL, '["Fantasi","Drama","Misteri"]', '[]', 79, 4.5, 5467, 1, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770729265, 1771241106);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlh2bond00002z39fnlct7dj', 'Nikah Instan, Cinta Tak Terduga', 'Dipaksa oleh sahabatnya untuk kencan buta, Melati Sari tak sengaja bertemu Direktur Utama Rizky Pratama. Tanpa banyak pertimbangan, mereka memutuskan menikah secara kilat. Pernikahan yang awalnya hanya kebetulan, justru membawa mereka menemukan cinta sejati dan kebahagiaan yang tak terduga.', 'https://stream.shortlovers.id/melolo/nikah-instan-cinta-tak-terduga/cover.jpg', NULL, '["Bisnis","Romantis","Drama"]', '[]', 100, 4.5, 1870, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770730668, 1771184180);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlhatcer0000cslhbrbdupkj', 'Cinta Membara yang Menyiksa', 'Setelah menikah tiga tahun, Icha Tora baru menyadari bahwa dia mencintai orang yang salah. Suaminya yang bernama Hasan Isga selingkuh, putrinya meninggal, sedangkan dia dimasukkan ke rumah sakit jiwa. Tiga hal ini membuat Icha hampir putus asa. Namun, kemunculan Yesa Fura bagaikan secercah cahaya dalam kegelapan. Akan seperti apa perjalanan cinta mereka?', 'https://stream.shortlovers.id/melolo/cinta-membara-yang-menyiksa/cover.jpg', NULL, '["Romantis","Drama"]', '[]', 69, 4.5, 1130, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770744929, 1771184180);
