INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlhejmnl0000leg3e7c64llx', 'Jodoh Tidak Akan Lari Ke Mana', 'Yani Yadi bertemu CEO Jason Sidik saat bekerja, dan keduanya punya hubungan yang tidak terduga. Cincin keluarga yang diberi Jason ke Yani direbut oleh Yuni Yadi, putri kandung dari orang tua angkat Yani. Jason mengira Yuni wanita pada malam itu dan membawanya pulang ke rumah. Kemudian, kakek kandung Yani akhirnya menemukannya, dan Yani muncul kembali ke depan semua orang.', 'https://stream.shortlovers.id/melolo/jodoh-tidak-akan-lari-ke-mana/cover.jpg', NULL, '["Keluarga","Bisnis","Romantis","Drama"]', '[]', 100, 4.5, 2395, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770751194, 1771184180);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlhf71ck00001693h9wi4kvr', 'Cinta Tak Terduga', 'Bella, seorang mahasiswi yang ekonominya pas-pasan, tanpa sengaja melakukan cinta satu malam dengan Ian, CEO dingin yang memiliki masalah kesuburan, dan akhirnya hamil anak kembar tiga. Sejak saat itu, hidupnya berubah oleh cinta dan perhatian dari keluarga Ian. Akankah cinta mereka bertahan?', 'https://stream.shortlovers.id/melolo/cinta-tak-terduga/cover.jpg', NULL, '["Keluarga","Bisnis","Romantis","Drama"]', '[]', 78, 4.5, 3488, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770752286, 1771184180);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlhg9v180000me961c5yk5uc', 'Diusir Dari Rumah, Saya Mewarisi Miliaran', 'Setelah Maya menemukan putri kandungnya di keluarga Muntofa, dia diusir dari rumah. Nenek Suharti membawanya dan mengatur agar dia bekerja di perusahaan pria tersebut. Seiring waktu, keduanya mulai menjalin hubungan, dan cinta perlahan tumbuh di antara mereka. Sementara itu, identitas asli Maya mulai terungkap secara perlahan.', 'https://stream.shortlovers.id/melolo/diusir-dari-rumah-saya-mewarisi-miliaran/cover.jpg', NULL, '["Drama","Romantis","Keluarga","Bisnis"]', '[]', 100, 4.5, 5303, 1, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770754098, 1771182904);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlhh8cwd0000gjhwjia7qpeu', 'Pilihan antara Dua Cinta', 'Sejak diadopsi oleh Keluarga Pratama, Rani Wijaya yakin masa depannya adalah menikah dengan Rama Pratama. Namun, kehadiran Raka, anak tak sah keluarga, perlahan mengubah segalanya. Semakin Raka mendekat, Rani pun sadar bahwa ia bukan sekadar kakak baginya—perasaan dan pilihan hidupnya mulai diuji oleh cinta yang tak terduga.', 'https://stream.shortlovers.id/melolo/pilihan-antara-dua-cinta/cover.jpg', NULL, '["Drama","Romantis","Keluarga"]', '[]', 80, 4.5, 1908, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770755707, 1771184180);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlhko8z70000eigx8pv08psm', 'Pacar Sewaanku Ternyata Bos Besar', 'Karena paksaan ibunya untuk menikah, dia mencari pacar sewaan. Siapa sangka pacar sewaan ini begitu hebat hingga ibunya langsung memaksa untuk langsung menikah. Dia berjanji untuk mendukung dan tidak mengganggu hidup pacar sewaannya ini, tetapi seiring berjalannya waktu, dia semakin melihat kehebatan pacar sewaannya.', 'https://stream.shortlovers.id/melolo/pacar-sewaanku-ternyata-bos-besar/cover.jpg', NULL, '["Bisnis","Romantis","Drama","Keluarga"]', '[]', 97, 4.5, 2688, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770761487, 1771184180);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlhlmwf20000842b6emo1ne1', 'Harta, Tahta Dan Ketulusan', 'Lina Pratama terjebak dalam pernikahan kontrak dan dikhianati oleh suami serta sahabatnya. Demi balas dendam, ia mendekati Raka Pradipta, pria misterius yang ternyata adalah Ketua Utama dengan identitas tersembunyi. Di tengah konflik batin dan permainan identitas, Lina mulai jatuh cinta, namun wasiat ibu menghalangi langkahnya.', 'https://stream.shortlovers.id/melolo/harta-tahta-dan-ketulusan/cover.jpg', NULL, '["Misteri","Romantis","Drama","Keluarga"]', '[]', 80, 4.5, 4305, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770763104, 1771182890);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlhlz2740000qj5yb84doal6', 'Kisah Dua Putri yang Tertukar', 'Lia Aryani memilih meninggalkan hidup mewah demi bekerja di perusahaan biasa. Tanpa disadari, perusahaan itu milik keluarganya sendiri. Di tengah berbagai kejutan dan kisah cinta lucu, Lia belajar tentang arti keluarga dan cinta sejati. Akhirnya, ia menemukan kebahagiaan bersama pria idamannya dan meneruskan warisan keluarga.', 'https://stream.shortlovers.id/melolo/kisah-dua-putri-yang-tertukar/cover.jpg', NULL, '["Romantis","Komedi","Drama","Bisnis","Keluarga"]', '[]', 33, 4.5, 4872, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770763671, 1771184180);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlhmcvtu0000p3zhc40as62n', 'Ibu Pengasuh dan Bayi Misterius', 'Anindya yang kehilangan ingatan bekerja sebagai pengasuh bayi di keluarga Pradipta demi biaya kuliah. Ia merawat bayi misterius, lalu terungkap sebagai ibu kandung lewat tes DNA. Arman pun menikah pura-pura dengannya. Raisa berusaha menjatuhkan Anindya, tapi dibongkar oleh Arman.', 'https://stream.shortlovers.id/melolo/ibu-pengasuh-dan-bayi-misterius/cover.jpg', NULL, '["Misteri","Romantis","Drama","Keluarga"]', '[]', 42, 4.5, 5526, 1, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770764316, 1771193956);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlhn1a8r0000hdo0pdzubn57', 'Idola Gila yang Memikat Hati', 'Indah Lestari, seorang pekerja kantoran, tiba-tiba terbangun sebagai selebriti kontroversial dengan kemampuan membaca pikiran hewan. Dengan kecerdikan dan bantuan Rizky Pratama, Indah mengungkap identitas aslinya, membongkar tipu muslihat, dan berhasil membalikkan keadaan di dunia hiburan, sekaligus menemukan cinta sejatinya.', 'https://stream.shortlovers.id/melolo/idola-gila-yang-memikat-hati/cover.jpg', NULL, '["Romantis","Drama","Keluarga"]', '[]', 78, 4.5, 1656, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Mandarin', 1770765455, 1771182793);
