INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlisfip001wytlqemr8yv7d9', 'Dusta Terakhir', 'Kinar, cucu Keluarga Sani, dipenjara usai mewarisi harta kakek. Pura-pura gila, ia rencanakan balas dendam dengan memanipulasi Yori, pangeran Negara Kilau. Saat Keluarga Sani hancur, Yori mengaku tahu tipu muslihatnya. "Aku rela kamu manfaatkan," katanya sambil memeluk Kinar.', 'https://stream.shortlovers.id/melolo/dusta-terakhir/cover.webp', NULL, '["Misteri"]', '[]', 134, 4.5, 1218, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770834983, 1771044822);
