INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlisfix6026gtlqe893yfrbs', 'Gadis Desa yang Bangkit Kembali', 'Sari terlahir kembali sebagai gadis desa miskin dengan orang tua lemah, adik polos, dan tetangga yang suka membuat onar. Mengandalkan bakat memasak, ia mengolah buah haw dan kastanye, membuka warung hingga restoran, membeli bukit, dan membawa keluarganya bangkit serta memakmurkan desa.', 'https://stream.shortlovers.id/melolo/gadis-desa-yang-bangkit-kembali/cover.webp', NULL, '["Aksi","Kehidupan"]', '[]', 93, 4.5, 1612, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770834983, 1771044822);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlisfj1v02bntlqe622p2um5', 'Guru Hebat Ternyata Sang Ratu', 'Ratna Dewi, pemimpin Seruni, menyamar sebagai guru demi melindungi Akademi Cendekia warisan ibunya. Ia menghadapi siswa nakal, ancaman penutupan, dan gangguan Aditya Pratama. Dengan dukungan guru, para siswa masuk tiga besar kota. Saat Ratna difitnah, siswa bersatu membelanya hingga kebenaran terungkap dan sekolah terselamatkan.', 'https://stream.shortlovers.id/melolo/guru-hebat-ternyata-sang-ratu/cover.webp', NULL, '["Kehidupan"]', '[]', 80, 4.5, 1914, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770834984, 1771044822);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlisfj6f02g4tlqelld9a76s', 'Guru Pedas di Kelas F', 'Intan Pramudita, pewaris keluarga mafia, terlahir kembali dan menyamar sebagai Wali Kelas F di SMA Utama Nusantara untuk menebus masa lalu. Bersama para siswa, ia saling menyembuhkan luka dan menemukan makna hidup. Hubungannya dengan Rizky Adinata menghangat, keluarganya pun perlahan menerima pilihannya.', 'https://stream.shortlovers.id/melolo/guru-pedas-di-kelas-f/cover.webp', NULL, '["Kehidupan"]', '[]', 59, 4.5, 2874, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770834984, 1771044822);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlisfja602jftlqe2w568rn7', 'Ibu Rumah Tangga Bermuka Dua', 'Nirmala menikah dengan Rizky Pratama, namun saat bulan madu, ia menyaksikan Rizky membunuh ayahnya. Demi balas dendam, Nirmala mencari bukti kejahatan Rizky dan bertemu Danny Wijaya, pewaris asli keluarga Pratama. Bersama Danny, Nirmala mengungkap identitas palsu Rizky dan berhasil menjebloskannya ke penjara.', 'https://stream.shortlovers.id/melolo/ibu-rumah-tangga-bermuka-dua/cover.jpg', NULL, '["Drama Keluarga"]', '[]', 50, 4.5, 2252, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770834984, 1771044822);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlisfjcr02jstlqe4r03njq3', 'Ibu Tiri Jinak, Takdir Berubah', 'Indah Sari tiba-tiba menjadi ibu tiri jahat dalam keluarga Pratama, yang kelak membuat dua anak Tuan Aditya tumbuh menjadi penjahat. Demi bertahan hidup, ia mengubah sikap dan memperbaiki hubungan, tanpa tahu Tuan Aditya juga terlahir kembali. Dari kecurigaan, tumbuh cinta dan kehangatan keluarga.', 'https://stream.shortlovers.id/melolo/ibu-tiri-jinak-takdir-berubah/cover.webp', NULL, '["Drama Keluarga"]', '[]', 80, 4.5, 1391, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770834984, 1771044821);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlisfjhc02o9tlqeolkbiepo', 'Istri Adrian yang Buta', 'Keluarga Miller mengalami kebakaran besar dan seluruh anggotanya mati terbakar. Mata Amelia Miller jadi buta karena terkena asap kebakaran itu dan pengurus rumah keluarganya diambil oleh Felix. Felix bersekongkol dengan seorang perawat bernama Paula untuk membuat Amelia tidur dengan Adrian Davis dan hamil agar dia bisa memeras uang Adrian, tapi Amelia malah menikah dengan Adrian. Penglihatan Amelia sudah pulih, tetapi dia pura-pura buta dan fokus mencari uang untuk memulihkan Keluarga Miller.', 'https://stream.shortlovers.id/melolo/istri-adrian-yang-buta/cover.webp', NULL, '["Romantis"]', '[]', 85, 4.5, 2811, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770834984, 1771044821);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlisfjl302rktlqeg3wmf7hm', 'Kartu Super Penguasa Segalanya', 'Konon, saat berusia 18, orang-orang terpilih akan menerima kartu dengan "kekuatan super". Ada 52 kartu dengan kekuatan yang berbeda. Namun, Jason mendapat kartu yang bisa menguasai semua kekuatan itu. Ia berambisi untuk membalaskan dendam pada kelompok yang telah menghabisi kedua orang tuanya.', 'https://stream.shortlovers.id/melolo/kartu-super-penguasa-segalanya/cover.webp', NULL, '["Aksi"]', '[]', 59, 4.5, 2751, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770834984, 1771044821);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlisfjo302tdtlqeslfuk9rf', 'Kehidupan Kedua di Desa', 'Setelah dibunuh oleh orangtua angkat, Haris hidup kembali. Menyadari konspirasi orang tua angkatnya, ia menjual bukti dan menggunakan kekuatan misterius untuk memulai hidup baru. Di desa, ia mengubah nasib dengan ilmu pengetahuan dan pengalaman dua kehidupan, lalu meraih kesuksesan gemilang.', 'https://stream.shortlovers.id/melolo/kehidupan-kedua-di-desa/cover.webp', NULL, '["Kehidupan"]', '[]', 81, 4.5, 2141, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770834984, 1771044820);
