INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlkd0ue300vp13mdevfdl6lt', 'Cahaya Di Kegelapan', 'Saat Laura ingin memberi tahu suaminya kalau pengelihatannya sudah kembali, dia malah melihat suaminya sedang bermesraan dengan pembantunya. Laura merasa marah, akhirnya memutuskan untuk berpura-pura tetap buta. Setelah puas melampiaskan kemarahannya, dia jujur kepada suaminya, meminta cerai, dan pergi bersama anaknya. Tapi, ternyata saat anaknya kembali dari perkemahan sudah bukan anak kandungnya lagi! Laura kebingungan mencari anaknya... Di saat itu, dia mendapatkan bantuan dari Mira. Ternyata kedua wanita ini sama-sama terjebak dalam kegelapan, akhirnya mereka pun saling membantu.', 'https://stream.shortlovers.id/melolo/cahaya-di-kegelapan/cover.webp', NULL, '["Drama","Romantis","Keluarga"]', '[]', 83, 0, 2, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770930037, 1771180926);
