INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlkd0uvt00z213mdoo2eiu9s', 'Cinta Buta Membawa Luka', 'Putri Anindya, manajer dana sukses, memilih cinta buta pada Fajar Santoso hingga memutus hubungan dengan ayahnya, Surya Anindya. Setelah dikhianati dan kehilangan segalanya, ia menyadari ketulusan sang ayah. Melalui dua kehidupan, Putri belajar arti penyesalan, kasih sayang, dan makna keluarga.', 'https://stream.shortlovers.id/melolo/cinta-buta-membawa-luka/cover.webp', NULL, '["Romantis"]', '[]', 23, 0, 1, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770930037, 1771044807);
