INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlkd1cmc02y113mdfcx6apqa', 'Dua Dunia Satu Cinta', 'Nita Juniar, seorang pengacara sukses berusia 29 tahun yang hidupnya hanya memikirkan pekerjaan, dan Johan Salim, pewaris muda berusia 19 tahun dari keluarga konglomerat, tidak sengaja bertemu dan jatuh cinta. Perbedaan usia, latar belakang, dan status sosial membuat mereka harus memilih, akankah mereka kembali ke dunia asal mereka, atau berani menghancurkan batasan demi cinta?', 'https://stream.shortlovers.id/melolo/dua-dunia-satu-cinta/cover.webp', NULL, '["Romantis"]', '[]', 75, 0, 1, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770930060, 1771044720);
