INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlkd26lw058513mdm125dj3g', 'Keserakahan Ibu Tiri Siani Terhadap Keluarga Boris', 'Siani sudah menolong hidup kakek Burhan, jadi Siani menikah dengan Burhan. Akan tetapi, keluarga Burhan selain kakeknya, mengira Siani datang untuk mengambil warisan keluarga Burhan, sehingga Burhan tidak mau bertemu Siani, 3 tahun menikah, mereka sama sekali belum pernah ketemu. 3 tahun kemudian, waktu acara penyambutan kembalinya Burhan, demi mendapatkan uang yang banyak, Ibu tiri Siani diam diam menaruh obat tidur di dalam bir Siani, Siani tidak tahu dan langsung minum bir itu, sehingga dia berhubungan cinta di kamar bersama Burhan. Hari kedua bangun dari tidur, Siani awalnya mau kasih tahu Burhan kalau dia itu istrinya yang belum ketemu sama sekali, tapi Burhan menganggap dia sebagai pelayan khusus. Sehingga mereka berdua memulai serangkaian percobaan dan berakhir dengan hubungan cinta satu sama lain.', 'https://stream.shortlovers.id/melolo/keserakahan-ibu-tiri-siani-terhadap-keluarga-boris/cover.webp', NULL, '["Drama Keluarga"]', '[]', 102, 0, 1, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1770930099, 1771044715);
