INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlm4wymm00vlszsaihs7t8mf', 'Menantu Berkuasa', 'Henry adalah putra keluarga kaya yang menyamar menjadi orang miskin dan karena ini dia dan Jessika istrinya dipermalukan. Saat ini, keluarga Henry sedang menghadapi lawan yang kuat dan keluarganya meminta bantuannya. Henry setuju tapi dia tetap tidak mau membongkar identitasnya dan dia memutuskan kerja sama dengan perusahaan keluarga Jessika. Untuk menyelamatkan perusahaan mereka, Jessika dipaksa untuk menikah dengan keluarga lain. Akhirnya, Henry pun murka…', 'https://stream.shortlovers.id/melolo/menantu-berkuasa/cover.webp', NULL, '["Drama","Romantis","Bisnis","Keluarga","Misteri"]', '[]', 78, 0, 1, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1771037351, 1771180926);
