INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlnybvzj019gw3jy93ay8l5v', 'Sang Penguasa Tertinggi', 'Saat Rizky Pratama pergi, dua Mahatinggi memicu kekacauan di Majelis Agung. Rizky berhasil menenangkannya, tetapi ancaman baru muncul. Orang tuanya dihina Keluarga Tanu. Dia segera pergi menyelamatkannya dan menemukan ada kekuatan besar di balik mereka. Bagaimana Rizky akan menghadapinya?', 'https://stream.shortlovers.id/melolo/sang-penguasa-tertinggi/cover.webp', NULL, '["Aksi"]', '[]', 101, 0, 11, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1771147222, 1771241159);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlnyw3q001lvw3jy9x5lme11', 'Aku Saja yang Manjakan Mama', 'Bryan yang menggemaskan berlari masuk ke kantor polisi, menangis dan meminta polisi untuk menangkap kedua orang tuanya karena ayahnya telah meninggalkannya dan ibunya terlalu sibuk bekerja sehingga tidak bisa mengurusnya. Luke baru mengetahui di kantor polisi kalau dia punya seorang putra, ternyata bertahun-tahun yang lalu Anya berpura-pura mati untuk meninggalkannya. Dengan bantuan si kecil Bryan, keduanya akhirnya menyelesaikan kesalahpahaman dan kembali bersama.', 'https://stream.shortlovers.id/melolo/aku-saja-yang-manjakan-mama/cover.webp', NULL, '["Romantis"]', '[]', 99, 0, 3, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1771148165, 1771241211);
INSERT OR IGNORE INTO dramas (id, title, description, cover, banner, genres, tag_list, total_episodes, rating, views, likes, review_count, average_rating, status, is_vip, is_featured, is_active, age_rating, release_date, director, cast, country, language, created_at, updated_at) VALUES ('cmlnz5d0n01rkw3jylr8q9mft', 'Cinta di Masa Perang', 'Rama Hartono dan Rara menikah karena perjodohan, namun hidup membawa mereka terpisah. Tanpa sadar, mereka bertemu kembali sebagai orang asing dan Rama jatuh cinta pada Rara. Takdir mempertemukan mereka dalam satu malam penuh kejutan, hingga Rara hamil. Di tengah gejolak zaman, kisah cinta mereka pun dimulai.', 'https://stream.shortlovers.id/melolo/cinta-di-masa-perang/cover.webp', NULL, '["Romantis","Aksi"]', '[]', 80, 0, 1, 0, 0, 0, 'completed', 0, 0, 1, 'all', NULL, NULL, '[]', 'China', 'Indonesia', 1771148597, 1771149031);